        {
            -- spelldescstr = "cryptofdamnationdesc",
            code = "z03",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Ein Sitzungsneustart ist erforderlich, um die Zone zu aktualisieren    \nDie Kartenzone wird beim Öffnen einer anderen identischen Karte nicht zurückgesetzt    \nKarten können nur im Akt 5 Hölle Schwierigkeitsgrad geöffnet werden    \nTransmutiere diesen Gegenstand mit sich selbst, um ein permanentes Portal zu einem Endgame-Bereich zu öffnen    \n\nÿc0Enthält keinen Kartenboss    \nEnthält 100%% mehr reguläre Boss-Packs    \nKann {yellow}Schatzgoblins enthalten    \n\nÿc0Drop-Bias: Axt und Messer {gold}Antike Couponsÿc0, {purple}Verdorbene Turmalinÿc0 Erze    \nÿc0Monsterlevel: {green}100\n",
                enUS = "ÿc5需要重新启动游戏阶段以刷新区域\n开启另一张相同的地图时，区域不会重置\n地图只能在第五章地狱难度中开启\n将此物品直接放入赫拉迪姆方块合成，可开启通往终局区域的单局永久传送门\n\nÿc0不包含地图首领\n包含 100% 更多的普通首领群\n有机会出现 ÿc9宝藏哥布林ÿc0\n\nÿc0此地图掉落偏向: 斧头与匕首 ÿc4古代兑换券ÿc0、ÿc;污染碧玺ÿc0 矿石\nÿc0怪物等级：{green}100\n",
                esES = "{gray}Se requiere un reinicio de sesión para refrescar la zona    \nLa zona del mapa no se reiniciará al abrir otro mapa idéntico    \nLos mapas solo se pueden abrir en la dificultad infierno del acto 5    \nTransmuta este objeto consigo mismo para abrir un portal permanente a un área de final de juego    \n\nÿc0No contiene un jefe de mapa    \nContiene un 100%% más de grupos de jefes regulares    \nPuede contener {yellow}goblins del tesoro    \n\nÿc0Sesgo de Caída: Hacha y Cuchillo {gold}Cupones Antiguosÿc0, {purple}Turmalina Tóxicaÿc0 Minerales    \nÿc0Nivel de Monstruo: {green}100\n",
                esMX = "{gray}Se requiere un reinicio de sesión para refrescar la zona    \nLa zona del mapa no se reiniciará al abrir otro mapa idéntico    \nLos mapas solo se pueden abrir en la dificultad infierno del acto 5    \nTransmuta este objeto consigo mismo para abrir un portal permanente a un área de final de juego    \n\nÿc0No contiene un jefe de mapa    \nContiene un 100%% más de grupos de jefes regulares    \nPuede contener {yellow}goblins del tesoro    \n\nÿc0Sesgo de Caída: Hacha y Cuchillo {gold}Cupones Antiguosÿc0, {purple}Turmalina Tóxicaÿc0 Minerales    \nÿc0Nivel de Monstruo: {green}100\n",
                frFR = "{gray}Un redémarrage de session est nécessaire pour rafraîchir la zone    \nLa zone de la carte ne se réinitialisera pas en ouvrant une autre carte identique    \nLes cartes ne peuvent être ouvertes qu'en difficulté enfer acte 5    \nTransmutez cet objet avec lui-même pour ouvrir un portail permanent vers une zone de fin de jeu    \n\nÿc0Ne contient pas de boss de carte    \nContient 100 %% de packs de boss réguliers en plus    \nPeut contenir {yellow}gobelins de trésor    \n\nÿc0Biais de drop : Hache et Couteau {gold}Coupons Anciensÿc0, {purple}Tourmaline Corrompueÿc0 Minerais    \nÿc0Niveau de Monstre : {green}100\n",
                itIT = "{gray}È necessario un riavvio della sessione per aggiornare la zona    \nLa zona della mappa non si resetterà all'apertura di un'altra mappa identica    \nLe mappe possono essere aperte solo nella difficoltà inferno atto 5    \nTrasmuta questo oggetto con se stesso per aprire un portale permanente verso un'area di fine gioco    \n\nÿc0Non contiene un boss di mappa    \nContiene il 100%% in più di pacchetti di boss regolari    \nPuò contenere {yellow}goblin del tesoro    \n\nÿc0Bias di Drop: Ascia e Coltello {gold}Coupon Antichiÿc0, {purple}Tourmalina Contaminataÿc0 Minerali    \nÿc0Livello Mostro: {green}100\n",
                jaJP = "{gray}ゾーンを更新するにはセッションの再起動が必要です    \n同じ地図を開くとマップゾーンはリセットされません    \nマップはアクト5の地獄難易度でのみ開くことができます    \nこのアイテムを自分自身と変換すると、エンドゲームエリアへの永久ポータルが開きます    \n\nÿc0マップボスは含まれていません    \n通常のボスパックが100%%増加します    \n{yellow}トレジャーゴブリンを含む可能性があります    \n\nÿc0ドロップバイアス: 斧とナイフ {gold}古代クーポンÿc0、{purple}汚染されたトルマリンÿc0鉱石    \nÿc0モンスターレベル: {green}100\n",
                koKR = "{gray}존을 새로 고치려면 세션 재시작이 필요합니다.    \n동일한 맵을 열면 맵 존이 초기화되지 않습니다.    \n맵은 5막 지옥 난이도에서만 열 수 있습니다.    \n이 아이템을 자신과 변환하여 엔드게임 지역으로 가는 영구 포털을 엽니다.    \n\nÿc0맵 보스가 포함되어 있지 않습니다.    \n일반 보스 팩이 100%% 더 포함되어 있습니다.    \n{yellow}보물 고블린이 포함될 수 있습니다.    \n\nÿc0드롭 편향: 도끼 및 칼    \n{gold}고대 쿠폰ÿc0, {purple}오염된 투르말린ÿc0 광석    \nÿc0몬스터 레벨: {green}100\n",
                plPL = "{gray}Wymagana jest ponowna sesja, aby odświeżyć strefę    \nStrefa mapy nie zresetuje się po otwarciu innej identycznej mapy    \nMapy można otwierać tylko w piątym akcie na poziomie trudności piekła    \nPrzemień ten przedmiot z samym sobą, aby otworzyć stały portal do obszaru końcowego    \n\nÿc0Nie zawiera bossa mapy    \nZawiera 100%% więcej regularnych paczek bossów    \nMoże zawierać {yellow}skarbników    \n\nÿc0Preferencje upuszczania: Topór i Nóż {gold}Starożytne Kuponyÿc0, {purple}Zatrute Turmalinyÿc0 Rudy    \nÿc0Poziom potwora: {green}100\n",
                ptBR = "{gray}É necessário reiniciar a sessão para atualizar a zona    \nA zona do mapa não será redefinida ao abrir outro mapa idêntico    \nOs mapas só podem ser abertos na dificuldade infernal do ato 5    \nTransmute este item consigo mesmo para abrir um portal permanente para uma área de final de jogo    \n\nÿc0Não contém um chefe de mapa    \nContém 100%% mais pacotes de chefes regulares    \nPode conter {yellow}goblins do tesouro    \n\nÿc0Tendência de Drop: Machado e Faca {gold}Cupons Antigosÿc0, {purple}Minérios de Turmalina Corrompidaÿc0    \nÿc0Nível do Monstro: {green}100\n",
                ruRU = "{gray}Для обновления зоны требуется перезапуск сессии    \nЗона карты не сбросится при открытии другой идентичной карты    \nКарты можно открывать только на уровне сложности ад 5 акта    \nПреобразуйте этот предмет с самим собой, чтобы открыть постоянный портал в зону конца игры    \n\nÿc0Не содержит босса карты    \nСодержит на 100%% больше обычных пакетов боссов    \nМожет содержать {yellow}сокровищных гоблинов    \n\nÿc0Смещение дропа: Топор и Нож {gold}Древние Купоныÿc0, {purple}Зараженные Турмалиныÿc0 Руды    \nÿc0Уровень монстра: {green}100\n",
                zhCN = "ÿc5需要重新启动游戏阶段以刷新区域\n开启另一张相同的地图时，区域不会重置\n地图只能在第五章地狱难度中开启\n将此物品直接放入赫拉迪姆方块合成，可开启通往终局区域的单局永久传送门\n\nÿc0不包含地图首领\n包含 100% 更多的普通首领群\n有机会出现 ÿc9宝藏哥布林ÿc0\n\nÿc0此地图掉落偏向: 斧头与匕首 ÿc4古代兑换券ÿc0、ÿc;污染碧玺ÿc0 矿石\nÿc0怪物等级：{green}100\n",
                zhTW = "{gray}需要重新啟動會話以刷新區域    \n打開另一個相同地圖時，地圖區域不會重置    \n地圖只能在第五幕地獄難度中打開    \n將此物品與自身轉化以打開通往終局區域的永久傳送門    \n\nÿc0不包含地圖首領    \n包含100%%更多的常規首領包    \n可以包含{yellow}寶藏哥布林    \n\nÿc0掉落偏好：斧頭和刀具 {gold}古代券ÿc0，{purple}污染的電氣石ÿc0礦石    \nÿc0怪物等級：{green}100\n",
