        {
            -- spelldescstr = "ib2desc",
            code = "ib2",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Transmutieren Sie sich selbst, um die Seite umzublätternÿc0\n\nAlternativ können Sie beim Händler einen kostenlosen Token der Absolution erwerben.\nKlicken Sie einfach auf einen erlernten Wert, während Sie die Alt-Taste gedrückt halten, um zurückzusetzen.\nDas Zurücksetzen Ihrer Fertigkeits- und Attributspunkte ist in diesem Mod kostenlos.\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 2/9 页)ÿc0\n\n你也可以直接向NPC「阿卡拉」购买「赦免勋章」\n在按住 Alt 的同时点击已加点的属性即可重置\n在东日模组中，重置技能及属性点是完全免费的\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nAlternativamente, puedes comprar un token de absolución gratuito del vendedor.\nSimplemente haz clic en una estadística aprendida mientras presionas alt para reiniciar.\nReiniciar tus habilidades y puntos de estadística es gratis en este mod.\n",
                esMX = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nAlternativamente, puedes comprar un token de absolución gratuito del vendedor\nSimplemente haz clic en una estadística aprendida mientras presionas alt para reiniciar\nReiniciar tus puntos de habilidad y estadística es gratis en este mod\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\nAlternativement, vous pouvez acheter un jeton d'absolution gratuit auprès du vendeur\nIl suffit de cliquer sur une statistique apprise tout en maintenant alt pour réinitialiser\nRéinitialiser vos compétences et points de statistiques est gratuit dans ce mod\n",
                itIT = "{gray}Trasforma con se stesso per girare paginaÿc0\n\nIn alternativa, puoi acquistare un token di assoluzione gratuito dal venditore\nBasta cliccare su una statistica appresa mentre si preme alt per resettare\nResettare le tue abilità e punti statistica è gratuito in questo mod\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\nまた、ベンダーから無償の赦しのトークンを購入することもできます\n学んだステータスを押しながらaltを押してクリックするだけでリセットできます\nこのモッドでは、スキルとステータスポイントのリセットは無料です\n",
                koKR = "{gray}자신과 변환하여 페이지를 넘깁니다ÿc0\n\n대안으로, 상인에게서 무료 면죄 토큰을 구매할 수 있습니다\n배운 스탯을 클릭하면서 alt를 누르면 리셋할 수 있습니다\n이 모드에서는 스킬과 스탯 포인트 리셋이 무료입니다\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nAlternatywnie, możesz kupić darmowy token absolucji od sprzedawcy\nPo prostu kliknij na nauczony atrybut, trzymając alt, aby zresetować\nResetowanie swoich umiejętności i punktów atrybutów jest darmowe w tym modzie\n",
                ptBR = "{gray}Transmute-se para virar a páginaÿc0\n\nAlternativamente, você pode comprar um token gratuito de absolvição do vendedor\nBasta clicar em uma estatística aprendida enquanto pressiona alt para redefinir\nRedefinir seus pontos de habilidade e estatísticas é gratuito neste mod\n",
                ruRU = "{gray}Трансмутация с самим собой для переворота страницыÿc0\n\nВ качестве альтернативы вы можете приобрести бесплатный токен абсолюции у продавца\nПросто нажмите на изученную характеристику, удерживая alt, чтобы сбросить\nСброс ваших навыков и характеристик бесплатен в этом моде\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 2/9 页)ÿc0\n\n你也可以直接向NPC「阿卡拉」购买「赦免勋章」\n在按住 Alt 的同时点击已加点的属性即可重置\n在东日模组中，重置技能及属性点是完全免费的\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n或者，您可以從商販那裡購買一個免費的赦免代幣\n只需在按住 alt 的同時點擊已學習的屬性即可重置\n在此模組中，重置您的技能和屬性點是免費的\n",
