                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 3/9 页)ÿc0\n\n装备与其镶嵌物都不会消失\n使用「钥匙」与已镶嵌装备合成即可卸下所有镶嵌物，\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\ncon una llave sin perder tu objeto base o socketables\nSiempre puedes dessocketear cualquier objeto al transmutarlo\n",
                esMX = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\ncon una llave sin perder tu objeto base o elementos con huecos\nSiempre puedes dessocketear cualquier objeto al transmutarlo\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\navec une clé sans perdre votre objet de base ou vos socketables\nVous pouvez toujours désenchanter n'importe quel objet en le transmutant\n",
                itIT = "{gray}Trasforma con se stesso per girare la paginaÿc0\n\ncon una chiave senza perdere il tuo oggetto di base o gli oggetti incastonabili\nPuoi sempre rimuovere l'incastonatura di qualsiasi oggetto trasformandolo\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\nキーを使って、ベースアイテムやソケットアイテムを失うことなく\nアイテムを変換することで、いつでもソケットを外すことができます\n",
                koKR = "{gray}자기 자신과 변환하여 페이지를 넘깁니다ÿc0\n\n기본 아이템이나 소켓 아이템을 잃지 않고 키로\n항상 아이템을 변환하여 소켓을 해제할 수 있습니다.\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nz kluczem, nie tracąc swojego podstawowego przedmiotu ani wkładek\nZawsze możesz usunąć wkładkę z dowolnego przedmiotu, transmutując go\n",
                ptBR = "{gray}Transmute-se para virar a páginaÿc0\n\ncom uma chave sem perder seu item base ou encaixáveis\nVocê sempre pode remover qualquer encaixe de um item transmutando-o\n",
                ruRU = "{gray}Трансмутация с самим собой, чтобы перевернуть страницуÿc0\n\nс ключом, не теряя ваш базовый предмет или вставляемые предметы\nВы всегда можете извлечь любой предмет, трансмутировав его\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 3/9 页)ÿc0\n\n装备与其镶嵌物都不会消失\n使用「钥匙」与已镶嵌装备合成即可卸下所有镶嵌物，\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n使用鑰匙而不失去你的基礎物品或插槽物品\n你可以隨時通過轉化任何物品來卸下插槽。\n",
