        {
            -- spelldescstr = "ib4desc",
            code = "ib4",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Mit sich selbst transmutieren, um die Seite umzublätternÿc0\n\nWeitere Details finden Sie im Abschnitt „Karten“ der Dokumentation,\naber alle Endspielzonen können umgangen werden.\nBegegnen Sie Endspielzonen anstelle alter Kampagnenzonen,\nVerschiedene Kartenlayouts wurden geändert und Sie könnten\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 4/9 页)ÿc0\n\n更多细节请查看网站的地图章节\n新手开荒请避免进入「终局区域」\n若在通关途中遇到「终局区域」，代表你走错方向\n第二章、第三章与第五章的地图路线已重新调整，\n",
                esES = "{gray}Transmuta con sí mismo para pasar la páginaÿc0\n\nConsulta la sección de mapas en la documentación para más detalles,\npero todas las zonas de juego final se pueden eludir.\nEncuentra zonas de juego final en lugar de las antiguas zonas de campaña,\nSe han cambiado varios diseños de mapas y es posible que\n",
                esMX = "{gray}Transmuta con sí mismo para pasar la páginaÿc0\n\nConsulta la sección de mapas en la documentación para más detalles,\npero todas las zonas de juego final se pueden eludir.\nEncuentra zonas de juego final en lugar de las antiguas zonas de campaña,\nSe han cambiado varios diseños de mapas y es posible que\n",
                frFR = "{gray}Transmutez avec lui-même pour tourner la pageÿc0\n\nConsultez la section des cartes dans la documentation pour plus de détails,\nmais toutes les zones de fin de jeu peuvent être contournées.\nRencontrez des zones de fin de jeu à la place des anciennes zones de campagne,\nDiverses dispositions de cartes ont été modifiées et vous pourriez\n",
                itIT = "{gray}Trasmuta con se stesso per voltare paginaÿc0\n\nConsulta la sezione delle mappe nella documentazione per maggiori dettagli,\nma tutte le zone di fine gioco possono essere eluse.\nIncontra le zone di fine gioco al posto delle vecchie zone della campagna,\nVari layout delle mappe sono stati modificati e potresti\n",
                jaJP = "{gray}それ自体と合成してページをめくるÿc0\n\n詳細はドキュメントのマップセクションを参照してください。\nすべてのエンドゲームゾーンは回避可能です。\n古いキャンペーンゾーンの代わりにエンドゲームゾーンに遭遇し、\n様々なマップレイアウトが変更されており、あなたは\n",
                koKR = "{gray}책장을 넘기려면 자신과 함께 조합하십시오ÿc0\n\n자세한 내용은 설명서의 지도 섹션을 참조하십시오.\n모든 엔드게임 지역은 우회할 수 있습니다.\n기존 캠페인 지역 대신 엔드게임 지역을 마주하게 되며,\n다양한 지도 레이아웃이 변경되어 당신은\n",
                plPL = "{gray}Transmutuj ze samym sobą, aby przewrócić stronęÿc0\n\nAby uzyskać więcej szczegółów, zapoznaj się z sekcją map w dokumentacji,\nale wszystkie strefy końcowe można obejść.\nNapotykaj strefy końcowe w miejsce starych stref kampanii,\nRóżne układy map zostały zmienione i możesz\n",
                ptBR = "{gray}Transmuta consigo mesmo para virar a páginaÿc0\n\nConsulte a seção de mapas na documentação para mais detalhes,\nmas todas as zonas de fim de jogo podem ser contornadas.\nEncontre zonas de fim de jogo no lugar de antigas zonas de campanha,\nVários layouts de mapas foram alterados e você pode\n",
                ruRU = "{gray}Смешайте с самим собой, чтобы перевернуть страницуÿc0\n\nДля получения подробностей обратитесь к разделу карт в документации,\nно все зоны эндгейма можно обойти.\nЗоны эндгейма встречаются вместо старых зон кампании,\nМакеты различных карт были изменены, и вы можете\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 4/9 页)ÿc0\n\n更多细节请查看网站的地图章节\n新手开荒请避免进入「终局区域」\n若在通关途中遇到「终局区域」，代表你走错方向\n第二章、第三章与第五章的地图路线已重新调整，\n",
                zhTW = "{gray}與自身合成以翻頁ÿc0\n\n請參閱文檔中的地圖章節以了解更多細節\n但所有的終局區域都可以被規避\n在舊有的戰役區域中遇見終局區域，\n各種地圖佈局已更改，你可能會\n",
            }
        },
        {
            -- spelldescstr = "ib5desc",
            code = "ib5",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Transmutieren Sie sich selbst, um die Seite umzublätternÿc0\n\nKonsultieren Sie den Kartenabschnitt in der Dokumentation für weitere Details,\naber alle Endgame-Zonen können umgangen werden,\ntreffen Sie Endgame-Zonen anstelle von alten Kampagnenzonen,\nverschiedene Kartenlayouts wurden geändert und Sie könnten\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 5/9 页)ÿc0\n\n因此务必查看网站以取得更多资讯\n这只是整个制作系统的冰山一角，\n\n等级需求仅决定你是否能装备该物品\n你可以套用任意数量的词缀，\n{gold}「龙石强化」ÿc0 —— 将龙石词缀套用到装备上，{red}此操作无法还原ÿc0\n但每件装备一次只能进行一次锻造\n锻造词缀可套用到装备上，且锻造是可还原的， \n{gold}「锻造」ÿc0 —— 你可以使用「龙石」制作成「铁砧」，  \n东日的制作系统极为庞大\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nConsulta la sección del mapa en la documentación para más detalles\npero todas las zonas de final de juego pueden ser eludidas\nencuentra zonas de final de juego en lugar de zonas de la campaña antigua,\nVarios diseños de mapa han sido cambiados y podrías\n",
                esMX = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nConsulta la sección del mapa en la documentación para más detalles\npero todas las zonas de final de juego pueden ser eludidas\nencuentra zonas de final de juego en lugar de zonas de la campaña antigua,\nVarios diseños de mapa han sido cambiados y podrías\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\nConsultez la section carte dans la documentation pour plus de détails\nmais toutes les zones de fin de jeu peuvent être contournées\nrencontrer des zones de fin de jeu à la place des anciennes zones de campagne,\nDivers agencements de cartes ont été modifiés et vous pourriez\n",
                itIT = "{gray}Trasforma con se stesso per girare paginaÿc0\n\nConsulta la sezione della mappa nella documentazione per ulteriori dettagli\nma tutte le zone di fine gioco possono essere aggirate\nincontra zone di fine gioco al posto delle vecchie zone della campagna,\nVari layout della mappa sono stati modificati e potresti\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\n詳細についてはドキュメントのマップセクションを参照してくださいが、\nすべてのエンドゲームゾーンは回避可能です。\n古いキャンペーンゾーンの代わりにエンドゲームゾーンに遭遇します。\nさまざまなマップレイアウトが変更されているため、あなたはおそらく\n",
                koKR = "{gray}자기 자신과 변환하여 페이지를 넘깁니다ÿc0\n\n자세한 내용은 문서의 지도 섹션을 참조하십시오.\n하지만 모든 엔드게임 지역은 우회할 수 있습니다.\n구 캠페인 지역 대신 엔드게임 지역을 만날 수 있습니다.\n다양한 지도 레이아웃이 변경되었으며, 당신은\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nSkonsultuj sekcję mapy w dokumentacji, aby uzyskać więcej szczegółów,\nale wszystkie strefy końcowe można obejść,\nnapotkać strefy końcowe zamiast starych stref kampanii,\nRóżne układy map zostały zmienione i możesz\n",
                ptBR = "{gray}Transmutar consigo mesmo para virar a páginaÿc0\n\nConsulte a seção de mapas na documentação para mais detalhes\nmas todas as zonas de final de jogo podem ser contornadas\nencontrar zonas de final de jogo no lugar das zonas da campanha antiga,\nVários layouts de mapa foram alterados e você pode\n",
                ruRU = "{gray}Трансмутация с самим собой для переворота страницыÿc0\n\nОбратитесь к разделу карты в документации для получения дополнительных сведений,\nно все зоны конца игры могут быть обойдены,\nвстретите зоны конца игры вместо старых зон кампании,\nРазличные макеты карт были изменены, и вы можете\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 5/9 页)ÿc0\n\n因此务必查看网站以取得更多资讯\n这只是整个制作系统的冰山一角，\n\n等级需求仅决定你是否能装备该物品\n你可以套用任意数量的词缀，\n{gold}「龙石强化」ÿc0 —— 将龙石词缀套用到装备上，{red}此操作无法还原ÿc0\n但每件装备一次只能进行一次锻造\n锻造词缀可套用到装备上，且锻造是可还原的， \n{gold}「锻造」ÿc0 —— 你可以使用「龙石」制作成「铁砧」，  \n东日的制作系统极为庞大\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n請參閱文檔中的地圖部分以獲取更多詳細信息，但所有終局區域都可以繞過，遇到終局區域以取代舊的戰役區域，各種地圖佈局已經改變，您可能會\n",
            }
        },
        {
            -- spelldescstr = "ib6desc",
            code = "ib6",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Transmutieren Sie sich selbst, um die Seite umzublätternÿc0\n\nDie Organe können jedoch verwendet werden, um bestimmte Endgame-Gegenstände auf spezielle Weise zu verbessern, wobei das vorherrschende Rezept darin besteht, Ihre Ausrüstung zu optimieren. Monsterorgane werden in verschiedenen Handwerksrezepten verwendet,\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 6/9 页)ÿc0\n\n器官可以用来以特殊方式强化某些终局物品\n最常见的配方是对装备进行细部调整\n怪物器官被用于各种制作配方中，\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nSin embargo, los órganos pueden ser utilizados para mejorar ciertos objetos finales de maneras especiales, siendo la receta predominante modificar tu equipo. Los órganos de monstruos se utilizan en varias recetas de elaboración,\n",
                esMX = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nSin embargo, los órganos pueden ser utilizados para mejorar ciertos objetos finales de maneras especiales, siendo la receta predominante modificar tu equipo. Los órganos de monstruo se utilizan en varias recetas de creación,\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\nCependant, les organes peuvent être utilisés pour améliorer certains objets de fin de jeu de manière spéciale, la recette prédominante étant de bricoler votre équipement. Les organes de monstres sont utilisés dans diverses recettes de fabrication,\n",
                itIT = "{gray}Trasforma con se stesso per girare la paginaÿc0\n\nTuttavia, gli organi possono essere utilizzati per migliorare determinati oggetti di fine gioco in modi speciali, \nla ricetta predominante è modificare il tuo equipaggiamento. \nGli organi dei mostri sono utilizzati in varie ricette di crafting,\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\nただし、臓器は特定のエンドゲームアイテムを特別な方法で改善するために使用できます。\n主なレシピは、装備を改造することです。\nモンスターの臓器は、さまざまなクラフトレシピで使用されます。\n",
                koKR = "{gray}자신과 변환하여 페이지를 넘깁니다ÿc0\n\n그러나, 장기는 특정 엔드게임 아이템을 특별한 방법으로 개선하는 데 사용될 수 있습니다.\n주요 레시피는 장비를 조작하는 것입니다.\n몬스터 장기는 다양한 제작 레시피에 사용됩니다.\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nJednak organy mogą być używane do ulepszania niektórych przedmiotów końcowych w specjalny sposób, \na dominującym przepisem jest majsterkowanie przy swoim ekwipunku. \nOrgany potworów są używane w różnych przepisach rzemieślniczych,\n",
                ptBR = "{gray}Transmutar consigo mesmo para virar a páginaÿc0\n\nNo entanto, os órgãos podem ser usados para melhorar certos itens de final de jogo de maneiras especiais, sendo a receita predominante a modificação do seu equipamento. Órgãos de monstros são usados em várias receitas de criação,\n",
                ruRU = "{gray}Трансмутация с самим собой, чтобы перевернуть страницуÿc0\n\nОднако органы могут быть использованы для улучшения определенных предметов в конце игры особым образом, \nпреобладающий рецепт - это модификация вашего снаряжения. \nОрганы монстров используются в различных рецептах крафта,\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 6/9 页)ÿc0\n\n器官可以用来以特殊方式强化某些终局物品\n最常见的配方是对装备进行细部调整\n怪物器官被用于各种制作配方中，\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n然而，這些器官可以用來以特殊方式改善某些終局物品，主要的配方是調整你的裝備。怪物器官用於各種製作配方，\n",
            }
        },
        {
            -- spelldescstr = "ib7desc",
            code = "ib7",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Transmutieren Sie sich selbst, um die Seite umzublätternÿc0\n\nkann im Neuwurf-Orb bis zu einer einzigartigen Variante gerollt werden,\num Ihre Ausrüstung schrittweise zu verbessern. Zum Beispiel 49 magische Ringe/Amulette,\num fast alles zu lagern, was Sie finden. Lagerplätze können ebenfalls verwendet werden\n{gold}Lagerplätzeÿc0 - Sie können von Gheed gekauft und verwendet werden.\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 7/9 页)ÿc0\n\n「重铸宝珠」可重铸暗金装备\n「重铸宝珠」可逐步提升你的装备。例如，49 个魔法戒指／护身符\n「储物袋」可储存对应的物品\n{gold}「各类储物袋」ÿc0 —— 可以从NPC「基德」购买，\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nse puede obtener en el Orbe de Repetición hasta una variante única\npara mejorar gradualmente tu equipo. Por ejemplo, 49 anillos/amuletos mágicos\npara almacenar casi todo lo que encuentres. Los almacenadores también se pueden usar\n{gold}Almacenadoresÿc0 - Se pueden comprar a Gheed y ser usados\n",
                esMX = "{gray}Transmutar consigo mismo para pasar la páginaÿc0\n\nse puede obtener en el Orbe de Re-roll hasta una variante única\npara mejorar gradualmente tu equipo. Por ejemplo, 49 anillos/amuletos mágicos\npara almacenar casi todo lo que encuentres. Los almacenadores también se pueden usar\n{gold}Almacenadoresÿc0 - Se pueden comprar a Gheed y ser utilizados\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\npeut être relancé dans l'Orbe de Relance jusqu'à une variante unique\npour améliorer progressivement votre équipement. Par exemple, 49 anneaux/amulettes magiques\npour stocker presque tout ce que vous trouvez. Les Stockers peuvent également être utilisés\n{gold}Stockersÿc0 - Ils peuvent être achetés auprès de Gheed et être utilisés\n",
                itIT = "{gray}Trasforma con se stesso per girare la paginaÿc0\n\npuò essere rilanciato nell'Orb di Rilancio fino a una variante unica\nper migliorare progressivamente il tuo equipaggiamento. Ad esempio, 49 anelli/amuleti magici\nper conservare quasi tutto ciò che trovi. Gli Stocker possono essere utilizzati\n{gold}Stockerÿc0 - Possono essere acquistati da Gheed e utilizzati\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\nユニークバリアントまでロール可能で、装備を段階的に改善できます。例えば、49個の魔法の指輪/アミュレットを見つけたほぼすべてを保管できます。ストッカーも使用可能です\n{gold}ストッカーÿc0 - ギードから購入でき、使用できます\n",
                koKR = "{gray}자기 자신과 변환하여 페이지를 넘깁니다ÿc0\n\n고유 변형으로 다시 굴릴 수 있으며\n장비를 점진적으로 개선할 수 있습니다. 예를 들어, 49개의 마법 반지/부적\n발견한 거의 모든 것을 저장할 수 있습니다. 재고 관리자는 또한 사용할 수 있습니다\n{gold}재고 관리자ÿc0 - 기드에게서 구입할 수 있으며 사용할 수 있습니다\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nmoże być przetaczane w Kulce Przewracania do unikalnej wersji\naby stopniowo poprawić swój ekwipunek. Na przykład, 49 magicznych pierścieni/amuletów\naby przechować prawie wszystko, co znajdziesz. Magazynki mogą być również używane\n{gold}Magazynkiÿc0 - Można je kupić od Gheed'a i używać\n",
                ptBR = "{gray}Transmutar consigo mesmo para virar a páginaÿc0\n\npode ser refeito no Orbe de Repetição até uma variante única\npara melhorar gradualmente seu equipamento. Por exemplo, 49 anéis/amuletos mágicos\npara armazenar quase tudo que você encontra. Estoqueiros também podem ser usados\n{gold}Estoqueirosÿc0 - Eles podem ser comprados de Gheed e usados\n",
                ruRU = "{gray}Трансмутация с самим собой для переворота страницыÿc0\n\nможет быть переработано в Орбе Переработки до уникального варианта\nдля поэтапного улучшения вашего снаряжения. Например, 49 магических колец/амулетов\nдля хранения почти всего, что вы находите. Хранилища также могут быть использованы\n{gold}Хранилищаÿc0 - Их можно купить у Гида и использовать\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 7/9 页)ÿc0\n\n「重铸宝珠」可重铸暗金装备\n「重铸宝珠」可逐步提升你的装备。例如，49 个魔法戒指／护身符\n「储物袋」可储存对应的物品\n{gold}「各类储物袋」ÿc0 —— 可以从NPC「基德」购买，\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n可以在重滾寶珠中滾出獨特變體\n以逐步改善你的裝備。例如，49個魔法戒指/護身符\n來儲存幾乎所有你找到的物品。庫存者也可以使用\n{gold}庫存者ÿc0 - 可以從吉德那裡購買並使用\n",
            }
        },
        {
            -- spelldescstr = "ib8desc",
            code = "ib8",
            location = { "onplayer", "equipped", "atvendor" },
            prefix = {
                deDE = "{gray}Transmutieren Sie sich selbst, um die Seite umzublätternÿc0\n\nmehrere untere Runen aus einer einzigen, indem Sie sie im Runenlager speichern\nSie können 2-3 sockelbare normale Ausrüstungsgegenstände von Charsi kaufen und erhalten\nüberprüfen Sie die Runenwortseite in der Dokumentation auf nützliche\nRunenworte sind in diesem Mod mächtig, also stellen Sie sicher, dass Sie\n",
                enUS = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 8/9 页)ÿc0\n\n并将高阶符文存入「符文储物袋」以分解成多个低阶符文。\n你可以从恰西购买 2–3 孔的普通装备，\n\n因此务必查看网站中的符文之语页面\n「新符」取得容易，建议优先制作；「原符」取得难度较高。\n符文之语在此模组中非常强大，分为「新符」与「原符」。\n",
                esES = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nmúltiples runas inferiores de una sola almacenándola en el Almacén de Runas\nPuedes comprar 2-3 objetos normales con huecos de Charsi y obtener\nconsulta la página de runas en la documentación para ver si hay alguna útil\nLas runas son poderosas en este mod, así que asegúrate de\n",
                esMX = "{gray}Transmuta contigo mismo para pasar la páginaÿc0\n\nmúltiples runas inferiores de una sola almacenándola en el Almacenador de Runas\nPuedes comprar equipo normal con 2-3 huecos de Charsi y obtener\nconsulta la página de runas en la documentación para ver si hay alguna útil\nLas runas son poderosas en este mod, así que asegúrate de\n",
                frFR = "{gray}Transmute avec lui-même pour tourner la pageÿc0\n\nplusieurs runes inférieures à partir d'une seule en la stockant dans le Stockeur de Runes\nVous pouvez acheter 2-3 équipements normaux avec emplacements chez Charsi et obtenir\nvérifiez la page des runewords dans la documentation pour en trouver des utiles\nLes runewords sont puissants dans ce mod, alors assurez-vous de\n",
                itIT = "{gray}Trasforma con se stesso per girare la paginaÿc0\n\npiù rune inferiori da una singola memorizzandola nello Stoccaggio Rune\nPuoi acquistare 2-3 equipaggiamenti normali con socket da Charsi e ottenere\ncontrolla la pagina delle rune nella documentazione per eventuali utili\nLe rune sono potenti in questo mod, quindi assicurati di\n",
                jaJP = "{gray}自分自身と変換してページをめくるÿc0\n\n単一のルーンをルーンストッカーに保存することで、複数の下位ルーンを得ることができます\nチャルシから2-3個のソケット付きの通常装備を購入し、手に入れましょう\n役立つものがないか、ドキュメントのルーンワードページを確認してください\nこのモッドではルーンワードが強力なので、必ず確認してください\n",
                koKR = "{gray}자신과 변환하여 페이지를 넘깁니다ÿc0\n\n하나의 하급 룬에서 여러 개의 하급 룬을 만들 수 있으며, 룬 저장소에 저장합니다.\nCharsi에게서 2-3개의 소켓이 있는 일반 장비를 구매할 수 있으며,\n유용한 룬어드에 대한 정보는 문서의 룬어드 페이지를 확인하세요.\n이 모드에서 룬어드는 강력하므로 반드시 확인하세요.\n",
                plPL = "{gray}Transmutuj z samym sobą, aby przewrócić stronęÿc0\n\nwiele niższych run z jednej, przechowując ją w Magazynie Run\nMożesz kupić 2-3 normalne przedmioty z gniazdami od Charsi i zdobyć\nsprawdź stronę runicznych słów w dokumentacji, aby znaleźć przydatne\nRuniczne słowa są potężne w tym modzie, więc upewnij się, że\n",
                ptBR = "{gray}Transmutar consigo mesmo para virar a páginaÿc0\n\nmúltiplas runas inferiores a partir de uma única, armazenando-a no Armazenador de Runas\nVocê pode comprar 2-3 equipamentos normais com soquetes da Charsi e obter\nverifique a página de runas na documentação para quaisquer úteis\nAs runas são poderosas neste mod, então certifique-se de\n",
                ruRU = "{gray}Трансмутация с самим собой, чтобы перевернуть страницуÿc0\n\nнесколько нижних рун из одной, сохранив её в Хранилище рун\nВы можете купить 2-3 обычных предмета с сокетами у Чарси и получить\nпроверьте страницу рун в документации на наличие полезных\nРунические слова мощные в этом моде, так что убедитесь, что\n",
                zhCN = "{gray}放入魔盒转化即可翻页查看更多内容{green}(第 8/9 页)ÿc0\n\n并将高阶符文存入「符文储物袋」以分解成多个低阶符文。\n你可以从恰西购买 2–3 孔的普通装备，\n\n因此务必查看网站中的符文之语页面\n「新符」取得容易，建议优先制作；「原符」取得难度较高。\n符文之语在此模组中非常强大，分为「新符」与「原符」。\n",
                zhTW = "{gray}與自身轉化以翻頁ÿc0\n\n從單一的低級符文中轉換多個，方法是將其儲存於符文儲存器中\n你可以從查爾西那裡購買2-3個插槽的普通裝備並獲得\n查看文檔中的符文詞頁面以獲取任何有用的符文詞\n符文詞在此模組中非常強大，因此請確保\n",
            }
